#include <omp.h>

#include <chrono>
#include <cstddef>
#include <cstdint>
#include <cstdio>
#include <cstring>

#include "mix_kernels_cpu.h"

#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct half2 {
  uint16_t x;
  uint16_t y;
};

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <class T>
inline bool equal(const T a, const T b) {
  return b == a;
}

template <>
inline half2 conv_int<half2>(const int i) {
  const uint16_t v = static_cast<uint16_t>(i);
  return half2{v, v};
}

template <>
inline half2 mad<half2>(const half2 a, const half2, const half2) {
  return a;
}

template <>
inline bool equal<half2>(const half2 a, const half2 b) {
  return a.x == b.x && a.y == b.y;
}

template <class T, int blockdim, unsigned int granularity,
          unsigned int fusion_degree, unsigned int compute_iterations,
          bool TemperateUnroll>
void benchmark_func(T seed, T* g_data, int total_blocks) {
  (void)TemperateUnroll;

  const unsigned int blockSize = blockdim;
  const int stride = blockSize;
  const long long big_stride =
      static_cast<long long>(total_blocks) * blockSize * granularity;
  const long long total_threads = static_cast<long long>(total_blocks) * blockSize;

#pragma omp parallel for schedule(static)
  for (long long linear_tid = 0; linear_tid < total_threads; ++linear_tid) {
    const int blockIdx = static_cast<int>(linear_tid / blockSize);
    const int threadIdx = static_cast<int>(linear_tid % blockSize);
    const long long idx =
        static_cast<long long>(blockIdx) * blockSize * granularity + threadIdx;

    T tmps[granularity];
    for (int k = 0; k < static_cast<int>(fusion_degree); k++) {
      for (int j = 0; j < static_cast<int>(granularity); j++) {
        tmps[j] = g_data[idx + static_cast<long long>(j) * stride +
                         static_cast<long long>(k) * big_stride];

        for (int i = 0; i < static_cast<int>(compute_iterations); i++) {
          tmps[j] = mad(tmps[j], tmps[j], seed);
        }
      }

      T sum = conv_int<T>(0);
      for (int j = 0; j < static_cast<int>(granularity); j = j + 2) {
        sum = mad(tmps[j], tmps[j + 1], sum);
      }

      if (equal(sum, conv_int<T>(-1))) {
        g_data[idx + static_cast<long long>(k) * big_stride] = sum;
      }
    }
  }
}

template <class F>
static float measure_ms(F&& f) {
  const auto start = std::chrono::high_resolution_clock::now();
  f();
  const auto stop = std::chrono::high_resolution_clock::now();
  return std::chrono::duration<float, std::milli>(stop - start).count();
}

void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
  const int TOTAL_REDUCED_BLOCKS = static_cast<int>(reduced_grid_size / BLOCK_SIZE);

  if (TOTAL_REDUCED_BLOCKS <= 0) return;

  benchmark_func<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true>(
      static_cast<short>(1), reinterpret_cast<short*>(cd), TOTAL_REDUCED_BLOCKS);
}

template <unsigned int compute_iterations>
void runbench(double* cd, long size, bool doHalfs) {
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const int BLOCK_SIZE = 256;
  const int TOTAL_BLOCKS = static_cast<int>(compute_grid_size / BLOCK_SIZE);
  const long long computations =
      (ELEMENTS_PER_THREAD * static_cast<long long>(compute_grid_size) +
       (2LL * ELEMENTS_PER_THREAD * compute_iterations) *
           static_cast<long long>(compute_grid_size)) *
      FUSION_DEGREE;
  const long long memoryoperations = size;

  float kernel_time_mad_sp = 0.f;
  float kernel_time_mad_dp = 0.f;
  float kernel_time_mad_hp = 0.f;
  float kernel_time_mad_int = 0.f;

  if (TOTAL_BLOCKS > 0) {
    kernel_time_mad_sp = measure_ms([&]() {
      benchmark_func<float, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, false>(1.0f,
                                                reinterpret_cast<float*>(cd),
                                                TOTAL_BLOCKS);
    });

    kernel_time_mad_dp = measure_ms([&]() {
      benchmark_func<double, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, false>(1.0, cd, TOTAL_BLOCKS);
    });

    if (doHalfs) {
      kernel_time_mad_hp = measure_ms([&]() {
        half2 h_ones;
        h_ones.x = static_cast<uint16_t>(15360);
        h_ones.y = static_cast<uint16_t>(15360);
        benchmark_func<half2, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                       compute_iterations, false>(
            h_ones, reinterpret_cast<half2*>(cd), TOTAL_BLOCKS);
      });
    }

    kernel_time_mad_int = measure_ms([&]() {
      benchmark_func<int, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, true>(1, reinterpret_cast<int*>(cd),
                                               TOTAL_BLOCKS);
    });
  }

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(half2)) / kernel_time_mad_hp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

